<div class="vi">
<svg viewBox="0 0 700 420" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="32" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">Sa Thải Tại Polygon Labs: Bốn Năm Liên Tiếp</text>
  <g font-family="sans-serif">
    <rect x="20" y="60" width="155" height="120" rx="10" fill="#18181b" stroke="#3f3f46" stroke-width="1.3"/>
    <text x="97" y="86" fill="#e4e4e7" text-anchor="middle" font-size="15" font-weight="700">2023</text>
